24	const PROCESSING_FEE = 5;
25	
26	const BASE_PRICE_BY_TYPE: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	  rune: 25,
32	  moonstone: 25,
33	};
34	
35	const basePriceFor = (item: Item): number => BASE_PRICE_BY_TYPE[item.type];
36	
37	const COMPONENT_BLOCK_SIZE = 3;
38	const COMPONENT_BLOCK_PRICE = 60;
39	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
40	
41	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
42	
43	const sumBasePrices = (items: Item[]): number =>
44	  items.reduce((s, i) => s + basePriceFor(i), 0);
45	
46	const groupByType = (items: Item[]): Map<string, Item[]> => {
47	  const map = new Map<string, Item[]>();
48	  for (const item of items) {
49	    const list = map.get(item.type) ?? [];
50	    list.push(item);
51	    map.set(item.type, list);
52	  }
53	  return map;
54	};
55	
56	const priceForComponentGroup = (group: Item[]): number =>
57	  group.length === COMPONENT_BLOCK_SIZE
58	    ? COMPONENT_BLOCK_PRICE
59	    : sumBasePrices(group);
60	
61	const componentsPremium = (components: Item[]): number =>
62	  Array.from(groupByType(components).values())
63	    .reduce((sum, group) => sum + priceForComponentGroup(group), 0);
64	
65	const itemsBasePremium = (items: Item[]): number => {
66	  const components = items.filter(isComponent);
67	  const nonComponents = items.filter((i) => !isComponent(i));
68	  return sumBasePrices(nonComponents) + componentsPremium(components);
69	};
