71	const CURSE_SURCHARGE_RATE = 0.5;
72	const HIGH_ENCHANTMENT_RATE = 0.3;
73	const HIGH_ENCHANTMENT_THRESHOLD = 5;
74	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
75	const LOYALTY_DISCOUNT_RATE = 0.2;
76	const LOYALTY_YEARS_THRESHOLD = 2;
77	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
78	
79	const perItemSurchargeRate = (item: Item): number =>
80	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
81	  ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_RATE : 0);
82	
83	const itemSurcharges = (items: Item[]): number =>
84	  items.reduce((sum, item) => sum + basePriceFor(item) * perItemSurchargeRate(item), 0);
85	
86	const isLoyal = (customer: Customer): boolean =>
87	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
88	
89	const loyaltyDiscountFor = (base: number, customer: Customer): number =>
90	  isLoyal(customer) ? base * LOYALTY_DISCOUNT_RATE : 0;
91	
92	const quotePremium = (step: QuoteStep, customer: Customer, stepIndex: number): number => {
93	  const base = itemsBasePremium(step.items);
94	  const followUpDiscount = stepIndex > 0 ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
95	  const total = base
96	    + itemSurcharges(step.items)
97	    + base * FIRST_INSURANCE_SURCHARGE_RATE
98	    - loyaltyDiscountFor(base, customer)
99	    - followUpDiscount
100	    + PROCESSING_FEE;
101	  return Math.ceil(total);
102	};
103	
104	export const runScenario = (scenario: Scenario): ScenarioResult => ({
105	  results: scenario.steps.map((step, i) => ({ premium: quotePremium(step, scenario.customer, i) })),
106	});
